// Allow importing CSS and static asset files without type errors
declare module '*.css'
declare module '*.scss'
declare module '*.sass'
declare module '*.less'
declare module '*.png'
declare module '*.jpg'
declare module '*.jpeg'
declare module '*.gif'
declare module '*.webp'
declare module '*.svg'
declare module '*.module.css'
declare module '*.module.scss'

// Declare packages without types
declare module 'next-themes'

export {}
